DROP TABLE IF EXISTS saorafael_document_rows CASCADE;
DROP TABLE IF EXISTS saorafael_document_metadata CASCADE;
DROP TABLE IF EXISTS saorafael_chat_message CASCADE;

-- 1. Tabela de Arquivos
CREATE TABLE saorafael_document_metadata (
    id TEXT PRIMARY KEY,
    title TEXT,
    url TEXT,
    created_at TIMESTAMP DEFAULT NOW(),
    schema TEXT,
    session_id TEXT
);

-- 2. Tabela de Linhas (Excel/CSV)
CREATE TABLE saorafael_document_rows (
    id SERIAL PRIMARY KEY,
    dataset_id TEXT REFERENCES saorafael_document_metadata(id) ON DELETE CASCADE,
    row_data JSONB
);

-- 3. Tabela de Memória do Chat
CREATE TABLE saorafael_chat_message (
    id SERIAL PRIMARY KEY,
    session_id TEXT NOT NULL,
    message JSONB NOT NULL,
    created_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX saorafael_idx_chat_message_session_id ON saorafael_chat_message(session_id);


-- Tabela de Orçamentos (Wizard Submissions)
CREATE TABLE IF NOT EXISTS saorafael_wizard_submission (
    id SERIAL PRIMARY KEY,
    protocol TEXT UNIQUE NOT NULL,
    session_id TEXT,
    user_id UUID,
    status TEXT DEFAULT 'submitted',
    form_data JSONB NOT NULL,
    submitted_at TIMESTAMP DEFAULT NOW(),
    processed_at TIMESTAMP,
    notes TEXT
);
CREATE INDEX IF NOT EXISTS idx_wizard_sub_user ON saorafael_wizard_submission(user_id);
CREATE INDEX IF NOT EXISTS idx_wizard_sub_protocol ON saorafael_wizard_submission(protocol);
CREATE INDEX IF NOT EXISTS idx_wizard_sub_status ON saorafael_wizard_submission(status);

-- 1. Remove Histórico de Chat Antigo
DELETE FROM saorafael_chat_message;

-- 2. Remove Vetores Antigos
DELETE FROM saorafael_documents
WHERE metadata->>'session_id' IS NOT NULL;

-- 3. Remove Arquivos/Metadados Antigos
DELETE FROM saorafael_document_metadata
WHERE session_id IS NOT NULL;

